const BATCH_LIMIT = 1;

function clean(value) {
  if (value === undefined || value === null) return '';
  return String(value).trim();
}

function status(value) {
  return clean(value).toLowerCase();
}

function isActiveRoute(value) {
  const route = status(value);
  return route === 'active listing' || route === 'active listing + cma';
}

function hasExistingAiBlurb(row) {
  const pgPackStatus = status(row['PG Pack Status']);
  const pgPackNotes = status(row['PG Pack Notes']);
  return (
    pgPackStatus === 'ai blurb drafted' ||
    pgPackStatus === 'ai blurb inserted' ||
    pgPackStatus === 'ready for pg review' ||
    pgPackNotes.includes('module 4b completed')
  );
}

const output = [];

for (const item of items) {
  const row = item.json;

  if (!isActiveRoute(row['Clarity Route'])) continue;
  if (clean(row['Automation Eligible']).toLowerCase() !== 'yes') continue;
  if (!clean(row['PG Blurb Output Link'])) continue;
  if (hasExistingAiBlurb(row)) continue;

  output.push({
    json: {
      ...row,
      'Module 4B Selected': 'Yes',
      'Module 4B Notes': 'Selected for AI PG blurb generation and insertion into existing PG Pack Google Doc',
    },
  });

  if (output.length >= BATCH_LIMIT) break;
}

return output;

const OPENAI_MODEL = 'gpt-4.1-mini';
const STANDARD_CTA = 'Contact us to arrange a viewing today.';

function clean(value) {
  if (value === undefined || value === null) return '';
  return String(value).trim();
}

function pick(row, names) {
  for (const name of names) {
    const value = clean(row[name]);
    if (value) return value;
  }
  return '';
}

function numberFrom(value) {
  const raw = clean(value).replace(/,/g, '');
  const match = raw.match(/\d+(\.\d+)?/);
  return match ? Number(match[0]) : null;
}

function privacyFloorPhrase(value) {
  const n = numberFrom(value);
  if (!n) return '';
  if (n >= 30) return 'very high-floor';
  if (n >= 20) return 'high-floor';
  if (n >= 15) return 'above 15th floor';
  if (n >= 10) return 'above 10th floor';
  if (n >= 6) return 'mid-floor';
  if (n >= 2) return 'low-floor';
  return '';
}

function extractDocId(url) {
  const text = clean(url);
  const match = text.match(/\/document\/d\/([a-zA-Z0-9_-]+)/);
  if (match) return match[1];
  return text;
}

function compactObject(obj) {
  const out = {};
  for (const [key, value] of Object.entries(obj)) {
    const cleaned = clean(value);
    if (cleaned) out[key] = cleaned;
  }
  return out;
}

const output = [];

for (const item of items) {
  const row = item.json;

  const projectName = pick(row, ['Project Name', 'Project', 'Development Name', 'Building Name']);
  const listingType = pick(row, ['Listing Type', 'Sale/Rent', 'Transaction Type']);
  const propertyType = pick(row, ['Property Type', 'Property Category', 'Type']);
  const bedrooms = pick(row, ['Bedrooms', 'Bedroom', 'No. of Bedrooms', 'Beds']);
  const bathrooms = pick(row, ['Bathrooms', 'Bathroom', 'No. of Bathrooms', 'Baths']);
  const floorArea = pick(row, ['Floor Area', 'Size', 'Area', 'Built-up Area', 'Approx Size']);
  const askingPrice = pick(row, ['Asking Price', 'Price', 'Listing Price', 'Rental Asking', 'Rent']);
  const psf = pick(row, ['Asking PSF', 'PSF', 'Price PSF', 'Rent PSF']);
  const tenure = pick(row, ['Tenure']);
  const district = pick(row, ['District']);
  const streetName = pick(row, ['Street Name', 'Street', 'Address']);
  const matchedAddress = pick(row, ['OneMap Matched Address', 'Matched Address']);
  const postalCode = pick(row, ['Postal Code', 'Postal']);
  const floorWording = privacyFloorPhrase(pick(row, ['Level', 'Floor', 'Storey', 'Floor Level']));

  const facts = compactObject({
    'Project / development': projectName,
    'Listing type': listingType,
    'Property type': propertyType,
    'Bedrooms': bedrooms,
    'Bathrooms': bathrooms,
    'Floor area': floorArea,
    'Asking price / rent': askingPrice,
    'PSF': psf,
    'Tenure': tenure,
    'District': district,
    'Street / area': streetName || matchedAddress,
    'Postal code': postalCode,
    'Privacy-safe floor wording': floorWording,
  });

  const userPrompt = [
    'Generate a PropertyGuru-ready listing blurb for this Singapore property.',
    '',
    'Property facts:',
    JSON.stringify(facts, null, 2),
    '',
    'Mandatory output rules:',
    '- Output only the final listing copy.',
    '- Start with one concise opening paragraph.',
    '- Then use dash-led selling points, one point per line.',
    `- End with this CTA: "${STANDARD_CTA}"`,
    '- Do not use a heading such as "Why this unit".',
    '- Do not reveal exact unit number, exact stack, or exact level.',
    '- Use only the privacy-safe floor wording provided, if useful.',
    '- Do not say "top floor".',
    '- Do not claim unverified views, renovated condition, premium stack, corner stack, privacy, layout advantages, or floorplan attributes unless directly supported by the facts.',
    '- If a point is not supported by the facts, omit it rather than guessing.',
    '- Keep the tone professional, clear, and suitable for Singapore PropertyGuru.',
    '- Keep it concise enough for a listing description.'
  ].join('\n');

  output.push({
    json: {
      ...row,
      'PG Pack Document ID': extractDocId(row['PG Blurb Output Link']),
      'OpenAI Model': OPENAI_MODEL,
      'OpenAI Request Body': {
        model: OPENAI_MODEL,
        input: [
          {
            role: 'system',
            content: 'You are a careful Singapore real estate listing copywriter. You write privacy-safe PropertyGuru listing copy and never invent unit-specific claims.'
          },
          {
            role: 'user',
            content: userPrompt
          }
        ],
        temperature: 0.35,
        max_output_tokens: 900
      }
    },
  });
}

return output;

function clean(value) {
  if (value === undefined || value === null) return '';
  return String(value).trim();
}

function singaporeTimestamp() {
  const now = new Date();
  const singaporeTime = new Date(now.toLocaleString('en-US', { timeZone: 'Asia/Singapore' }));
  const yyyy = singaporeTime.getFullYear();
  const mm = String(singaporeTime.getMonth() + 1).padStart(2, '0');
  const dd = String(singaporeTime.getDate()).padStart(2, '0');
  const hh = String(singaporeTime.getHours()).padStart(2, '0');
  const min = String(singaporeTime.getMinutes()).padStart(2, '0');
  return `${yyyy}-${mm}-${dd} ${hh}:${min}`;
}

function extractOpenAiText(response) {
  if (typeof response.output_text === 'string') return response.output_text;

  if (Array.isArray(response.output)) {
    const parts = [];
    for (const outputItem of response.output) {
      if (Array.isArray(outputItem.content)) {
        for (const contentItem of outputItem.content) {
          if (typeof contentItem.text === 'string') parts.push(contentItem.text);
          if (typeof contentItem.output_text === 'string') parts.push(contentItem.output_text);
        }
      }
    }
    if (parts.length) return parts.join('\n').trim();
  }

  if (Array.isArray(response.choices)) {
    const text = response.choices
      .map(choice => choice?.message?.content || choice?.text || '')
      .filter(Boolean)
      .join('\n');
    if (text) return text;
  }

  return '';
}

function stripUnsafeUnitReferences(text) {
  let out = clean(text);

  // Remove common exact Singapore unit reference patterns, e.g. #32-16, #08-01, Unit #12-34.
  out = out.replace(/\bUnit\s*#?\s*\d{1,2}\s*[-/]\s*\d{1,4}\b/gi, 'unit');
  out = out.replace(/#\s*\d{1,2}\s*[-/]\s*\d{1,4}\b/g, '');
  out = out.replace(/\b\d{1,2}(st|nd|rd|th)\s+floor\s+unit\b/gi, 'privacy-safe floor unit');

  // Remove forbidden heading if the model added it.
  out = out.replace(/^\s*(why this unit|why this could be your next home)\s*:?\s*$/gim, '');

  return out.replace(/\n{3,}/g, '\n\n').trim();
}

function ensureDashLedPoints(text) {
  const lines = text.split('\n');
  return lines.map(line => {
    const trimmed = line.trim();
    if (!trimmed) return '';
    if (/^[•*]\s+/.test(trimmed)) return '- ' + trimmed.replace(/^[•*]\s+/, '');
    return line;
  }).join('\n').replace(/\n{3,}/g, '\n\n').trim();
}

const selectedRows = $('Build OpenAI PG Blurb Request').all();
const now = singaporeTimestamp();
const output = [];

for (let i = 0; i < items.length; i++) {
  const selectedRow = selectedRows[i]?.json || {};
  const response = items[i]?.json || {};
  let blurb = extractOpenAiText(response);

  if (!blurb) {
    throw new Error(`Module 4B: OpenAI response did not contain usable listing copy for Source Key ${clean(selectedRow['Source Key'])}`);
  }

  blurb = ensureDashLedPoints(stripUnsafeUnitReferences(blurb));

  const docInsertText = [
    '',
    '',
    '---',
    '',
    'PROPERTYGURU LISTING BLURB - AI DRAFT',
    `Generated by Clarity V2 Module 4B: ${now}`,
    '',
    blurb,
    '',
    'Internal review note: Please check all claims before publishing to PropertyGuru. Exact unit number has been intentionally excluded from the listing copy.',
    ''
  ].join('\n');

  output.push({
    json: {
      ...selectedRow,
      'Generated PG Blurb': blurb,
      'Doc Insert Text': docInsertText,
      'PG Pack Last Updated': now,
      'PG Pack Status': 'AI Blurb Drafted',
      'PG Pack Review Status': 'Needs Review',
      'PG Pack Notes': `Module 4B completed: AI PG blurb inserted into existing PG Pack Google Doc using ${clean(selectedRow['OpenAI Model']) || 'OpenAI'}. Review required before publishing.`,
    },
  });
}

return output;

const preparedRows = $('Prepare PG Blurb Doc Insert').all();

const output = [];

for (let i = 0; i < items.length; i++) {
  const prepared = preparedRows[i]?.json || {};
  const docResponse = items[i]?.json || {};
  const sourceKey = prepared['Source Key'];

  if (!sourceKey) continue;

  output.push({
    json: {
      'Source Key': sourceKey,
      'Property Record ID': prepared['Property Record ID'],
      'PG Pack Status': prepared['PG Pack Status'],
      'PG Blurb Output Link': prepared['PG Blurb Output Link'],
      'PG Pack Last Updated': prepared['PG Pack Last Updated'],
      'PG Pack Review Status': prepared['PG Pack Review Status'],
      'PG Pack Notes': prepared['PG Pack Notes'],
      'PG Pack Document ID': prepared['PG Pack Document ID'] || docResponse.documentId || '',
    },
  });
}

return output;
